import React from "react";

const Contact = () => {
  return <div>
    <div
      className="hero-container"
      style={{ backgroundImage: `url('/images/h1.png')` }}
    ></div>
  <h1>Contact Us:</h1>
    <span>Fill this form to Contact me.</span>
    <p>Name:</p>
    <input type="text" placeholder="Enter your name" />

  </div>
};

export default Contact;
